function scoreRecord(rec) {
  const required = ["deviceId","ts","region","value"];
  let score = 0;
  required.forEach(k => { if (rec[k] !== undefined && rec[k] !== null) score += 0.25; });
  if (rec["firmwareVersion"]) score += 0.1;
  return Math.min(1, score);
}
```

